const path = require('path');

const urls = [
  'https://sitem.ssgcdn.com/71/39/38/item/1000282383971_i1_290.jpg',
  'https://sitem.ssgcdn.com/71/39/38/item/1000282383971_i1.jpg',
  'https://sitem.ssgcdn.com/51/87/42/item/1000560428751_i1_290.jpg',
  'https://sitem.ssgcdn.com/51/87/42/item/1000560428751_i1.jpg'
];

function download(url, filepath) {
  return new Promise((resolve, reject) => {
    const file = fs.createWriteStream(filepath);
    const options = {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
      },
      timeout: 10000
    };
    https.get(url, options, (res) => {
      if (res.statusCode !== 200) {
        file.close();
        fs.unlink(filepath, () => {});
        reject(new Error(`Status Code ${res.statusCode}`));
        return;
      }
      res.pipe(file);
      file.on('finish', () => {
        file.close(resolve);
      });
    }).on('error', (err) => {
      file.close();
      fs.unlink(filepath, () => {});
      reject(err);
    });
  });
}

async function run() {
  for (const url of urls) {
    const name = url.split('/').pop();
    const filepath = path.join(__dirname, name);
    console.log(`Downloading ${url}...`);
    try {
      await download(url, filepath);
      console.log(`  [성공] ${name} (${fs.statSync(filepath).size} bytes)`);
    } catch (e) {
      console.log(`  [실패] ${e.message}`);
    }
  }
}

run();
"

