"const http = require('https');
const fs = require('fs');

const url = 'https://browse.gmarket.co.kr/search?keyword=%ED%8F%AC%ED%85%8E%ED%86%A0%EC%B9%A9+%EC%98%A4%EB%A6%AC%EC%A7%80%EB%84%90';

