  headers: {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  }
}, (res) => {
  let html = '';
  res.on('data', chunk => html += chunk);
  res.on('end', () => {
    // Look for image links in Gmarket search HTML (image.gmarket.co.kr)
    const matches = html.match(/http[s]?:\/\/image\.gmarket\.co\.kr\/[^\s"']+/g);
    if (!matches) {
      console.log('No Gmarket images found.');
      return;
    }

    // Filter for typical product images (e.g. contain /kr/ or /toy/ or similar product paths, or just look at all of them)
    const imgUrls = [...new Set(matches)].filter(url => url.includes('/goods_img/') || url.includes('/kr/'));
    console.log('Found image URLs:', imgUrls.slice(0, 10));

    if (imgUrls.length > 0) {
      // Let's download the first image
      const targetUrl = imgUrls[0];
      console.log('Downloading:', targetUrl);
      http.get(targetUrl, (imgRes) => {
        const file = fs.createWriteStream('C:\\Users\\smile\\snack-picker\\images\\potetochip_new.png');
        imgRes.pipe(file);
        file.on('finish', () => {
          file.close();
          console.log('Download complete!');
        });
      });
    }
  });
}).on('error', (err) => {
  console.error('Error fetching search results:', err);
});
