"const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, 'data.js');
const fileContent = fs.readFileSync(filePath, 'utf8');

// We can load the data by evaluating/requiring it.
// Since it exports SNACK_DATA when module is defined, we can just require it!
const SNACK_DATA = require('./data.js');

// Update links that don't start with the new prefix (or that start with 'example' / other old placeholders)
// Actually, let's update any link that is NOT one of our 12 explicitly updated links.
// The explicitly updated links start with 'https://link.coupang.com/a/dYt' and are NOT 'https://link.coupang.com/a/dYt2P5DKma'.
// Wait! Let's be precise: any snack link that doesn't start with 'https://link.coupang.com/a/dYt' (except if it's already 'https://link.coupang.com/a/dYt2P5DKma' which is the new one)
// should be set to 'https://link.coupang.com/a/dYt2P5DKma'.
const targetLink = 'https://link.coupang.com/a/dYt2P5DKma';

let updatedCount = 0;
const updatedData = SNACK_DATA.map(snack => {
  if (!snack.link.startsWith('https://link.coupang.com/a/dYt')) {
    snack.link = targetLink;
    updatedCount++;
  }
  return snack;
});

// Now let's format it exactly like the original.
// Each object in the array should be formatted with JSON.stringify(snack, null, 2), but with 2 spaces indent for the fields.
const formattedObjects = updatedData.map(snack => {
  const lines = JSON.stringify(snack, null, 2).split('\n');
  // indent the lines of the object
  const indentedLines = lines.map((line, idx) => {
    if (idx === 0) return '  ' + line;
    return '  ' + line;
  }).join('\n');
  return indentedLines;
}).join(',\n');

const newContent = `const SNACK_DATA = [\n${formattedObjects}\n];\n\nif (typeof module !== 'undefined') {\n  module.exports = SNACK_DATA;\n}\n`;

fs.writeFileSync(filePath, newContent, 'utf8');
console.log(`Successfully updated ${updatedCount} placeholder links to ${targetLink}.`);
"

