":root {
  --bg-dark: #0f172a;
  --bg-gradient: linear-gradient(135deg, #1e1b4b, #312e81);
  --machine-body: linear-gradient(145deg, #ef4444, #b91c1c);
  --machine-rim: #f87171;
  --knob-bg: linear-gradient(145deg, #fbbf24, #d97706);
  --text-main: #f8fafc;
  --text-dim: #94a3b8;
  --accent: #f472b6;
  --glass: rgba(255, 255, 255, 0.15);
  --glass-border: rgba(255, 255, 255, 0.3);
  --radius: 12px;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Noto Sans KR', sans-serif;
  background: var(--bg-gradient);
  color: var(--text-main);
  min-height: 100vh;
  display: flex;
  justify-content: center;
  overflow-x: hidden;
  user-select: none;
}

.app-container {
  width: 100%;
  max-width: 480px;
  min-height: 100vh;
  background: rgba(0,0,0,0.2);
  box-shadow: 0 0 50px rgba(0,0,0,0.5);
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
}

.app-header {
  padding: 20px;
  text-align: center;
  font-family: 'Jua', sans-serif;
  font-size: 1.8rem;
