  box-shadow: 2px 4px 10px rgba(0,0,0,0.3);
}
.input-slot::after {
  /* Memo pad folded corner effect */
  content: '';
  position: absolute;
  bottom: 0;
  right: 0;
  width: 15px;
  height: 15px;
  background: rgba(255,255,255,0.2);
  border-top-left-radius: 4px;
  box-shadow: -2px -2px 5px rgba(0,0,0,0.2);
}

.slot-memo {
  width: 45px;
  height: 45px;
  border-radius: 2px;
  margin-bottom: 15px;
  box-shadow: 2px 2px 5px rgba(0,0,0,0.4);
  transition: all 0.3s ease;
  position: relative;
}
.slot-memo::before {
  content: '';
  position: absolute;
  top: -5px; left: 50%;
  transform: translateX(-50%);
  width: 20px; height: 10px;
  background: rgba(255,255,255,0.3);
  border-radius: 2px;
}

.input-slot input {
  width: 100%;
  background: transparent;
  border: none;
  border-bottom: 2px dashed rgba(255,255,255,0.3);
  color: #fff;
  text-align: center;
  font-size: 1rem;
  padding: 5px;
  outline: none;
  transition: border-color 0.3s;
}
.input-slot input:focus {
  border-bottom-color: var(--accent);
}

.action-area {
  margin-top: auto;
  padding-bottom: 20px;
}
.btn {
  border: none;
  border-radius: 30px;
  padding: 15px 20px;
  font-size: 1.1rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
}
.btn-primary {
  background: linear-gradient(135deg, #f472b6, #db2777);
  color: #fff;
  box-shadow: 0 5px 15px rgba(219, 39, 119, 0.4);
}
.btn-primary:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(219, 39, 119, 0.6);
}
.btn-primary:disabled {
  background: #475569;
  box-shadow: none;
  cursor: not-allowed;
  opacity: 0.7;
}
.btn-block { width: 100%; }"

